import{_ as e,c as t,o as a,a as o}from"./index.524cd724.js";const n={name:"AboutPage"},i={class:"container m-top"},r=o('<h1 data-v-7c451764>About This Website</h1><p data-v-7c451764>Welcome, dear reader.</p><p data-v-7c451764>On this website I write about topics that I care about. </p><p data-v-7c451764> Born and raised a Dutchman, I work as an <a href="https://forgefire.dev" data-v-7c451764>entrepreneur and artificial intelligence engineer.</a> Usually I spend my time figuring out if AI can solve a certain problems, do research, build prototypes and generally expand my knowledge on the subject. </p><p data-v-7c451764> Given my background in robotics and my work I tend to think a lot about AI. I try to get a grip on the major problems that we might face in the long term, and what we might to mitigate the challenges and risks. </p><p data-v-7c451764> Mostly I try to write content that is accessible to everyone, but once in a while I write very technical posts. I will try to make it clear which one is which so you can pick and choose what to read. </p><p data-v-7c451764> Other times I just write about anything that catches my attention. You might find writing on design, video games, music, finance or psychology. </p><p data-v-7c451764> I hope you will enjoy the journey. Thank you for reading my work. </p><p class="sign" data-v-7c451764> - Mickey Beurskens </p>',9),c=[r];function s(d,p,h,l,u,m){return a(),t("div",i,c)}var _=e(n,[["render",s],["__scopeId","data-v-7c451764"]]);export{_ as default};
